use std::sync::{Arc, Mutex};

fn create_closure() -> impl Fn() -> i32 {
    let data: Arc<Mutex<i32>> = Arc::new(Mutex::new(0));
    move || {
        let mut val = data.lock().unwrap();
        *val += 1;
        *val
    }
}

fn main() {
    let mut handles = vec![];
    for _ in 0..5 {
        let h = std::thread::spawn(create_closure);
        handles.push(h);
    }
    for handle in handles { _ = handle.join().unwrap(); }
}

